import React, { useState, useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import * as actions from '../../redux/actions';
import {
  Box,
  Container,
  Paper,
  TextField,
  Button,
  Typography,
  ToggleButtonGroup,
  ToggleButton,
  Avatar,
  List,
  ListItem,
  ListItemAvatar,
  ListItemText,
  Divider,
  Badge,
  Stack,
  Chip,
  IconButton,
  useMediaQuery,
  useTheme,
} from '@mui/material';
import FullCalendar from '@fullcalendar/react';
import dayGridPlugin from '@fullcalendar/daygrid';
import interactionPlugin from '@fullcalendar/interaction';
import SearchIcon from '@mui/icons-material/Search';
import CalendarMonthIcon from '@mui/icons-material/CalendarMonth';
import ViewListIcon from '@mui/icons-material/ViewList';
import PersonIcon from '@mui/icons-material/Person';
import AccessTimeIcon from '@mui/icons-material/AccessTime';
import PlaceIcon from '@mui/icons-material/Place';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import LocationOnIcon from '@mui/icons-material/LocationOn';
import ClearIcon from '@mui/icons-material/Clear';
import dayjs from 'dayjs';
import 'dayjs/locale/th';
import relativeTime from 'dayjs/plugin/relativeTime';
import _ from 'lodash';

dayjs.locale('th');
dayjs.extend(relativeTime);

export default function ManpowerCheckTimeStamp() {
  const dispatch = useDispatch();
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('sm'));

  const timestamp = useSelector((state) => state.timestamp);

  const [searchName, setSearchName] = useState('');
  const [viewMode, setViewMode] = useState('calendar');
  const [dateStart, setDateStart] = useState(
    dayjs().startOf('month').toISOString(),
  );
  const [dateEnd, setDateEnd] = useState(dayjs().endOf('month').toISOString());

  const handleSearch = () => {
    dispatch(
      actions.timestampAll({
        name: searchName,
      }),
    );
  };

  const handleClearSearch = () => {
    setSearchName('');
    dispatch(
      actions.timestampAll({
        name: '',
        status_checkIn: true,
        dateStart,
        dateEnd,
      }),
    );
  };

  const handleViewModeChange = (event, newMode) => {
    if (newMode !== null) {
      setViewMode(newMode);
    }
  };

  const calendarEvents = _.map(timestamp?.rows, (item) => ({
    id: item._id,
    title: `${item?.employee_firstname} ${item?.employee_lastname}`,
    date: dayjs(item?.createdAt).format('YYYY-MM-DD'),
    backgroundColor: item?.out_of_location ? '#dc3545' : '#28a745',
    borderColor: item?.out_of_location ? '#dc3545' : '#28a745',
    extendedProps: {
      ...item,
    },
  }));

  const renderSearchSection = () => (
    <Paper
      elevation={0}
      sx={{
        p: { xs: 2.5, sm: 3 },
        borderRadius: 4,
        background: 'linear-gradient(135deg, #ffffff 0%, #f8f9ff 100%)',
        boxShadow: '0 8px 24px rgba(102, 126, 234, 0.12)',
        border: '1px solid rgba(102, 126, 234, 0.1)',
        mb: 3,
      }}
    >
      <Typography
        variant="h5"
        sx={{
          fontWeight: 700,

          backgroundClip: 'text',
          WebkitBackgroundClip: 'text',
          WebkitTextFillColor: 'transparent',
          mb: 2,
          display: 'flex',
          alignItems: 'center',
          gap: 1,
        }}
      >
        <SearchIcon />
        ค้นหารายการลงเวลา
      </Typography>

      <Stack spacing={2}>
        <Box sx={{ display: 'flex', gap: 1.5, flexWrap: 'wrap' }}>
          <TextField
            label="ค้นหาชื่อพนักงาน"
            variant="outlined"
            value={searchName}
            onChange={(e) => setSearchName(e.target.value)}
            onKeyPress={(e) => {
              if (e.key === 'Enter') {
                handleSearch();
              }
            }}
            sx={{
              flex: 1,
              minWidth: 200,
              '& .MuiOutlinedInput-root': {
                borderRadius: 2.5,
                '&:hover fieldset': {
                  borderColor: '#667eea',
                },
                '&.Mui-focused fieldset': {
                  borderColor: '#667eea',
                },
              },
            }}
            InputProps={{
              endAdornment: searchName && (
                <IconButton size="small" onClick={handleClearSearch}>
                  <ClearIcon fontSize="small" />
                </IconButton>
              ),
            }}
          />

          <Button
            variant="contained"
            startIcon={<SearchIcon />}
            onClick={handleSearch}
            sx={{
              borderRadius: 2.5,
              px: 4,
              py: 1.5,
              fontWeight: 600,
              textTransform: 'none',
              background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
              boxShadow: '0 4px 12px rgba(102, 126, 234, 0.3)',
              '&:hover': {
                background: 'linear-gradient(135deg, #764ba2 0%, #667eea 100%)',
                boxShadow: '0 6px 16px rgba(102, 126, 234, 0.4)',
              },
            }}
          >
            ค้นหา
          </Button>
        </Box>

        <Box
          sx={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
            flexWrap: 'wrap',
            gap: 2,
          }}
        >
          <Chip
            icon={<PersonIcon />}
            label={`พบทั้งหมด ${timestamp?.rows?.length || 0} รายการ`}
            sx={{
              fontWeight: 600,
              fontSize: '0.95rem',
              py: 2.5,
              px: 1,
              background: 'linear-gradient(135deg, #e3f2fd 0%, #f3e5f5 100%)',
              border: '1px solid rgba(102, 126, 234, 0.2)',
            }}
          />

          <ToggleButtonGroup
            value={viewMode}
            exclusive
            onChange={handleViewModeChange}
            sx={{
              '& .MuiToggleButton-root': {
                borderRadius: 2,
                px: 3,
                py: 1,
                fontWeight: 600,
                textTransform: 'none',
                border: '1px solid rgba(102, 126, 234, 0.3)',
                '&.Mui-selected': {
                  background:
                    'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                  color: 'white',
                  '&:hover': {
                    background:
                      'linear-gradient(135deg, #764ba2 0%, #667eea 100%)',
                  },
                },
              },
            }}
          >
            <ToggleButton value="calendar">
              <CalendarMonthIcon sx={{ mr: 1 }} />
              ปฏิทิน
            </ToggleButton>
            <ToggleButton value="list">
              <ViewListIcon sx={{ mr: 1 }} />
              รายการ
            </ToggleButton>
          </ToggleButtonGroup>
        </Box>
      </Stack>
    </Paper>
  );

  const renderCalendarView = () => (
    <Paper
      elevation={0}
      sx={{
        p: { xs: 2, sm: 3 },
        borderRadius: 4,
        background: 'linear-gradient(135deg, #ffffff 0%, #f8f9ff 100%)',
        boxShadow: '0 8px 24px rgba(102, 126, 234, 0.12)',
        border: '1px solid rgba(102, 126, 234, 0.1)',
      }}
    >
      <FullCalendar
        plugins={[dayGridPlugin, interactionPlugin]}
        initialView="dayGridMonth"
        locale="th"
        events={calendarEvents}
        height="auto"
        headerToolbar={{
          left: 'prev,next today',
          center: 'title',
          right: 'dayGridMonth,dayGridWeek',
        }}
        eventClick={(info) => {
          const event = info.event;
          alert(
            `${event.title}\nเวลา: ${dayjs(
              event.extendedProps.createdAt,
            ).format('HH:mm น.')}`,
          );
        }}
        dayCellClassNames="custom-day-cell"
        eventClassNames="custom-event"
      />
    </Paper>
  );

  const renderListView = () => (
    <Paper
      elevation={0}
      sx={{
        borderRadius: 4,
        background: 'linear-gradient(135deg, #ffffff 0%, #f8f9ff 100%)',
        boxShadow: '0 8px 24px rgba(102, 126, 234, 0.12)',
        border: '1px solid rgba(102, 126, 234, 0.1)',
        overflow: 'hidden',
      }}
    >
      {_.isEmpty(timestamp?.rows) ? (
        <Box
          sx={{
            p: 6,
            textAlign: 'center',
            color: 'text.secondary',
          }}
        >
          <SearchIcon sx={{ fontSize: 64, opacity: 0.3, mb: 2 }} />
          <Typography variant="h6">ไม่พบรายการลงเวลา</Typography>
          <Typography variant="body2">
            ลองค้นหาด้วยชื่อพนักงานหรือปรับช่วงเวลา
          </Typography>
        </Box>
      ) : (
        <List sx={{ py: 0 }}>
          {_.map(timestamp?.rows, (item, index) => (
            <React.Fragment key={item._id || index}>
              <ListItem
                sx={{
                  py: 2.5,
                  px: { xs: 2, sm: 3 },
                  '&:hover': {
                    bgcolor: 'rgba(102, 126, 234, 0.05)',
                  },
                }}
              >
                <ListItemAvatar>
                  <Badge
                    overlap="circular"
                    anchorOrigin={{ vertical: 'bottom', horizontal: 'right' }}
                    badgeContent={
                      <CheckCircleIcon
                        sx={{
                          color: '#28a745',
                          fontSize: 20,
                          bgcolor: 'white',
                          borderRadius: '50%',
                        }}
                      />
                    }
                  >
                    <Avatar
                      src={item?.image}
                      sx={{
                        width: isMobile ? 48 : 56,
                        height: isMobile ? 48 : 56,
                        border: '2px solid #667eea',
                      }}
                    >
                      <PersonIcon />
                    </Avatar>
                  </Badge>
                </ListItemAvatar>

                <ListItemText
                  primary={
                    <Box>
                      <Typography variant="subtitle1" fontWeight="bold">
                        {item?.employee_firstname} {item?.employee_lastname}
                      </Typography>
                      <Box
                        display="flex"
                        alignItems="center"
                        gap={1}
                        mt={0.5}
                        flexWrap="wrap"
                      >
                        <Chip
                          icon={<AccessTimeIcon fontSize="small" />}
                          label={dayjs(item?.createdAt).format(
                            'DD/MM/YYYY HH:mm น.',
                          )}
                          size="small"
                          sx={{
                            bgcolor: '#e3f2fd',
                            fontWeight: 600,
                          }}
                        />
                        <Typography variant="caption" color="text.secondary">
                          ({dayjs(item?.createdAt).fromNow()})
                        </Typography>
                      </Box>
                    </Box>
                  }
                  secondary={
                    <Box sx={{ mt: 1.5 }}>
                      <Stack spacing={1}>
                        {item?.project_in?.name && (
                          <Box display="flex" alignItems="center" gap={0.5}>
                            <PlaceIcon fontSize="small" color="primary" />
                            <Typography variant="body2">
                              โครงการ: {item?.project_in?.name}
                            </Typography>
                          </Box>
                        )}

                        {item?.out_of_location && (
                          <Box display="flex" alignItems="center" gap={0.5}>
                            <LocationOnIcon fontSize="small" color="error" />
                            <Typography variant="body2" color="error">
                              อยู่นอกพื้นที่โครงการ
                            </Typography>
                          </Box>
                        )}

                        {item?.employeeType?.name && (
                          <Typography variant="caption" color="text.secondary">
                            ประเภท: {item?.employeeType?.name}
                          </Typography>
                        )}
                      </Stack>
                    </Box>
                  }
                />
              </ListItem>

              {index < timestamp?.rows?.length - 1 && (
                <Divider sx={{ borderColor: 'rgba(102, 126, 234, 0.1)' }} />
              )}
            </React.Fragment>
          ))}
        </List>
      )}
    </Paper>
  );

  return (
    <Box
      sx={{
        minHeight: '100vh',

        py: { xs: 2, sm: 4 },
        position: 'relative',
        '&::before': {
          content: '""',
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          background:
            'radial-gradient(circle at 20% 50%, rgba(255,255,255,0.1) 0%, transparent 50%)',
          pointerEvents: 'none',
        },
      }}
    >
      <Container maxWidth="lg" sx={{ position: 'relative', zIndex: 1 }}>
        {renderSearchSection()}
        {viewMode === 'calendar' ? renderCalendarView() : renderListView()}
      </Container>
    </Box>
  );
}
